INSERT INTO alerts (title, level, message, target_group, sent_by, is_active, ai_summary, created_at, updated_at) VALUES
('RED ALERT: Cyclone VAYU Approaching Odisha-AP Coast','critical','The India Meteorological Department has issued a RED alert for coastal Odisha and Andhra Pradesh. Cyclonic Storm VAYU has intensified into a Severe Cyclonic Storm and is expected to make landfall near Gopalpur, Odisha within 24 hours. Maximum sustained wind speed: 150-160 km/h gusting to 180 km/h. Dangerous storm surge of 2-4 metres expected along coastal areas. Mandatory evacuation ordered for all residents within 10 km of coastline. Relief camps are operational at 847 designated cyclone shelters across both states. NDRF teams have been deployed to Bhubaneswar, Puri, Berhampur, and Gopalpur. Do NOT venture into the sea under any circumstances. Keep identity documents and essential medicines in waterproof bags. Emergency helpline: 1078.','all',1,1,'RED ALERT: Cyclone VAYU approaching Odisha-AP coast. Landfall in 24 hrs. Winds 150-180 km/h. Storm surge 2-4 metres. Mandatory coastal evacuation. NDRF deployed. Call 1078.',NOW() - INTERVAL 2 HOUR,NOW()),
('CRITICAL FLOOD: Brahmaputra Above Danger Level — Assam','critical','The Central Water Commission reports the Brahmaputra River at Guwahati has reached 87.3 metres, crossing the danger level of 85.1 metres. Heavy rainfall upstream in Arunachal Pradesh (380mm in 48 hours) has caused embankment breaches in Dhubri, Barpeta, and Morigaon districts. Approximately 2.3 lakh people across 892 villages are currently affected. NDRF teams are conducting active rescue operations at Pathsala and Nalbari. Flood relief camps established at 234 schools and community halls across the state. Do not use flooded roads — NH-17 and NH-27 are partially submerged. All residents in low-lying areas must move to higher ground immediately. State flood helpline: 1800-345-3501.','all',1,1,'CRITICAL: Brahmaputra above danger level in Assam. 2.3 lakh people affected across 892 villages. NDRF deployed. Move to higher ground immediately. Helpline: 1800-345-3501.',NOW() - INTERVAL 5 HOUR,NOW()),
('ORANGE ALERT: Severe Heatwave — North India April 6 to 9 2026','warning','IMD has issued an Orange Alert for severe heatwave conditions across Delhi NCR, Rajasthan, Haryana, Punjab, and western Uttar Pradesh valid from April 6 to 9, 2026. Maximum temperatures are expected to reach 44-46 degrees Celsius. Heat Index may exceed 50 degrees due to combined heat and humidity effects. Health Advisory: Avoid all outdoor activity between 11am and 5pm. Drink minimum 3 litres of water per day. Wear loose light cotton clothing. Never leave children, elderly, or pets in parked vehicles — interior temperature reaches 70 degrees in 20 minutes. Construction sites must provide shade, water, and ORS to all workers. Night cooling centres are operational at 127 government schools across Delhi. ASHA workers are conducting daily doorstep wellness checks. Health helpline: 104.','all',1,1,'ORANGE ALERT: Severe heatwave 44-46 degrees across North India until April 9. Avoid outdoors 11am-5pm. Drink water every 30 mins. 127 cooling centres open in Delhi. Health helpline: 104.',NOW() - INTERVAL 1 DAY,NOW()),
('ADVISORY: M4.8 Earthquake Near Chamoli Uttarakhand','warning','The National Centre for Seismology has recorded a magnitude 4.8 earthquake at 02:34 IST today, with the epicentre located 42 km northeast of Chamoli, Uttarakhand at a shallow depth of 10 km. This falls in Zone V — India highest seismic risk category. No major damage or casualties have been reported so far. Aftershocks of magnitude 2.5 to 3.5 may occur in the coming 48 to 72 hours. Residents in Chamoli, Rudraprayag, Pithoragarh, and Bageshwar districts should inspect buildings for cracks especially at wall junctions, window corners, and where walls meet the ceiling or floor. Avoid entering cracked or damaged structures. Keep emergency kit accessible. DDMA helpline: 1800-180-4188.','all',1,1,'M4.8 earthquake near Chamoli Uttarakhand Zone V. Aftershocks possible 48-72 hrs. Inspect buildings for cracks. Avoid damaged structures. DDMA helpline: 1800-180-4188.',NOW() - INTERVAL 6 HOUR,NOW()),
('LANDSLIDE WARNING: NH-44 Blocked — Himachal Pradesh','warning','Extremely heavy rainfall of 210mm in 24 hours in Lahaul-Spiti and Kinnaur districts of Himachal Pradesh has triggered multiple landslides on NH-44 (Manali-Leh Highway) and NH-5 (Shimla-Kalka route). The Border Roads Organisation and HRTC have suspended all traffic between Rohtang Pass and Keylong until further notice. Approximately 800 tourists are currently stranded at Keylong and Sarchu rest houses. Helicopter rescue operations have commenced from Kullu Bhuntar airfield. Residents of Spiti Valley, Sangla Valley, and villages near the Satluj River basin must move to safer locations on higher ground immediately. Do not attempt to cross any flooded nullahs or streams on foot or by vehicle. District helpline Kullu: 01902-222340. HP Tourist helpline: 1100.','all',1,1,'WARNING: Multiple landslides on NH-44 Manali-Leh Highway. 800 tourists stranded. Helicopter rescue underway from Kullu. Avoid Rohtang Pass area entirely. HP Tourist helpline: 1100.',NOW() - INTERVAL 3 HOUR,NOW()),
('TSUNAMI WATCH: Andaman and Nicobar Islands','info','INCOIS has issued a Tsunami Watch for the Andaman and Nicobar Islands following a M7.1 undersea earthquake in the Sunda Trench at 15:22 UTC today. This is currently a WATCH status — not yet a full Warning. All coastal residents and tourists across the Andaman and Nicobar Islands should move away from beaches and low-lying coastal areas to higher ground immediately as a precaution. INCOIS is closely monitoring sea level gauges at Campbell Bay, Car Nicobar, and Port Blair. Estimated wave height if tsunami reaches the islands: 0.3 to 1.0 metres (moderate risk). All fishermen must return to port immediately. All scuba diving and snorkelling operations are suspended. Updates issued every 30 minutes on All India Radio Port Blair 684 kHz.','all',1,1,'TSUNAMI WATCH: Andaman and Nicobar Islands. M7.1 quake Sunda Trench. Move away from beaches to higher ground. Fishermen return to port now. AIR Port Blair 684 kHz for updates.',NOW() - INTERVAL 30 MINUTE,NOW()),
('HAZARDOUS AQI 418: Delhi-NCR Air Quality Emergency','info','Delhi and NCR districts including Gurgaon, Noida, Faridabad, and Ghaziabad have recorded an AQI of 418, classified as HAZARDOUS, due to a combination of stubble burning smoke from Punjab and Haryana and calm wind conditions trapping pollutants. PM2.5 concentration is currently 285 micrograms per cubic metre against the safe 24-hour limit of 25. GRAP Stage IV emergency restrictions are in force: all construction activity banned, schools and colleges operating in online mode, truck entry into Delhi restricted to essential goods, private vehicle odd-even scheme operational from 8am to 8pm. Health Advisory: Wear N95 or N99 masks outdoors — standard surgical masks do not filter PM2.5. Persons with asthma, heart disease, or diabetes and all children and elderly must stay strictly indoors. DPCC helpline: 1800-11-0093.','all',1,1,'HAZARDOUS AQI 418 Delhi-NCR. PM2.5 at 285 vs safe limit of 25. GRAP Stage IV active. Schools online. Wear N95 mask outdoors. Vulnerable groups stay indoors. DPCC: 1800-11-0093.',NOW() - INTERVAL 12 HOUR,NOW());
