INSERT INTO drills (type, date, building, participants, status, notes, created_by, created_at, updated_at) VALUES
('Earthquake Evacuation Drill','2026-04-08','IIIT Hyderabad Academic Block A, Gachibowli, Hyderabad',450,'scheduled','Annual mandatory earthquake drill for all students and faculty. Drop-Cover-Hold and staircase evacuation to assembly point at sports ground. NDRF trainer Mr. Suresh Kumar conducting briefing at 9:00 AM. Duration: 90 minutes including post-drill debriefing and written performance report.',1,NOW(),NOW()),
('Cyclone Preparedness Simulation','2026-04-10','Collectorate Building, Visakhapatnam, Andhra Pradesh',230,'scheduled','District-level cyclone response simulation with SDRF, Coast Guard Station Vizag, and Visakha Dairy. Scenario: Category 3 cyclone landfall in 36 hours. Mass evacuation coordination, shelter activation, supply pre-positioning at 15 shelters, and media briefing simulation. All 5 revenue divisional officers participating.',1,NOW(),NOW()),
('Hospital Mass Casualty Drill','2026-04-12','AIIMS Bhopal Trauma and Emergency Department',180,'scheduled','Disaster Medical Response drill simulating 50-casualty mass incident from railway accident. Triage using START protocol, hospital Emergency Operations Centre activation, coordination with 108 ambulance service, and family notification procedures. All ER and ICU staff mandatory. NDMA observer attending.',1,NOW(),NOW()),
('Fire Evacuation and Suppression Drill','2026-03-28','Infosys Campus Building 17 Electronic City Phase 2 Bengaluru',820,'completed','Quarterly fire drill per KSFE regulations. Scenario: electrical fire in server room. All 820 employees evacuated via 8 emergency staircases in 4 minutes 22 seconds against 5-minute target. Issue found: Emergency exit on 3rd floor east wing partially blocked. Corrective action issued to facilities team. All 12 fire wardens performed excellently.',1,NOW() - INTERVAL 9 DAY,NOW()),
('Flood Rescue Boat Operation Drill','2026-03-20','Bramhapuri Tehsil Headquarters, Chandrapur, Maharashtra',65,'completed','SDRF flood rescue team certification drill on Wardha River. Practiced: rapid boat deployment from trailer, casualty extraction from submerged vehicle, rooftop rescue using rope system, first aid in boat, and helicopter coordination by radio. All 65 SDRF personnel successfully recertified. 8 boats and 4 life-ring launchers deployed.',1,NOW() - INTERVAL 17 DAY,NOW()),
('School Earthquake Safety Programme','2026-03-15','Delhi Government School No 158, Mayur Vihar Phase 3',1200,'completed','NDMA School Safety Programme drill under National School Safety Programme. All 1200 students from Classes 1 to 12 participated. Drop-Cover-Hold drilled class-wise. 40 teachers trained as School Safety Marshals. Mock injury scenario with mannequins. District Magistrate East Delhi attended. School received NDMA School Safety Certificate.',1,NOW() - INTERVAL 22 DAY,NOW()),
('Industrial Chemical Spill Response Drill','2026-04-18','HPCL Refinery Mahul Mumbai Unit 4',120,'planned','Tier 2 mutual aid exercise simulating chlorine gas leak. Mumbai Fire Brigade HazMat team, MAHAD Industrial Cluster, and ONGC safety teams participating. PPE Level A suits deployed. Decontamination corridor at refinery gate. Evacuation of 800 metre radius simulated. MIDC Environment Officer observing.',1,NOW(),NOW()),
('Tsunami Coastal Evacuation Mock Drill','2026-04-20','Marina Beach Promenade, Chennai, Tamil Nadu',3500,'planned','INCOIS and Tamil Nadu State DDMA coordinating large coastal evacuation drill. 3500 fishermen and coastal residents evacuating to 8 designated tsunami vertical evacuation structures. Sirens tested at 10:00 AM. Coordination with Chennai Police, Revenue Department, and Fishing Harbour Authority.',1,NOW(),NOW()),
('Heatwave Response Protocol Training','2026-04-05','Rajkot Municipal Corporation Training Hall, Gujarat',95,'completed','Heat action plan training for 95 ASHA workers and health supervisors. Topics: recognizing heat exhaustion vs heatstroke, emergency cooling, ORS preparation, door-to-door wellness checks, data reporting. Conducted by Dr. Meena Joshi, District Medical Officer. Each participant received field kit with ORS sachets and thermometer.',1,NOW() - INTERVAL 1 DAY,NOW()),
('Night-time Earthquake Evacuation Drill','2026-05-02','Residential Township Sector 57, Gurugram, Haryana',2800,'planned','First-ever night-time earthquake drill in Gurugram at 2:00 AM. 2800 residents of 6 residential societies participating. Torch distribution to households on April 30. GMDA officials and Haryana SDMA coordinating. Objective: full building evacuation in under 8 minutes from any unit.',1,NOW(),NOW());
