INSERT INTO disaster_reports (user_id, disaster_type, location, description, severity, status, latitude, longitude, created_at, updated_at) VALUES
(1,'Landslide','Mundakkai and Chooralmala, Wayanad District, Kerala','On July 30 2024 two catastrophic landslides struck Mundakkai and Chooralmala villages at 2 AM while residents slept. Triggered by 572mm of rainfall in 48 hours — 400 percent above normal — saturating slopes largely deforested for tea and coffee plantations. 231 people were killed and 10,000 displaced. Approximately 280 houses and four bridges were destroyed. Indian Army, NDRF, Kerala Fire Force, and volunteers conducted rescue operations for 10 days. Primary causes: extreme rainfall, degraded forest cover on steep slopes, and complete absence of early warning systems. GSI now recommends mandatory slope stability assessments for all plantation areas in seismic Zone V.','critical','resolved',11.4534,76.1328,NOW() - INTERVAL 250 DAY,NOW()),
(1,'Cyclone','Nellore and Bapatla Districts AP and Chennai Tamil Nadu','Cyclone Michaung made landfall near Bapatla AP on December 5 2023 with sustained winds of 90-100 km/h causing unprecedented flooding in Chennai — worst in 8 years. Adyar and Cooum rivers overflowed, flooding Velachery, Mudichur, and Anna Nagar East. Two million people affected across AP and Tamil Nadu. 17 deaths reported — far fewer than the 500 deaths in 2015 Chennai floods due to improved early warning and NDRF pre-positioning. Key lesson: storm drain capacity and Pallikaranai wetlands conservation are critical for Chennai flood resilience.','high','resolved',13.9299,79.9800,NOW() - INTERVAL 120 DAY,NOW()),
(1,'Heatwave','Delhi NCR, Rajasthan, Haryana, Punjab and Western UP','Prolonged heatwave April 1-9 2026 brought temperatures of 44-46 degrees Celsius across North India. Eight heat-related deaths reported. An estimated 45 million people affected across five states. Hospitals reported 340 percent increase in heat exhaustion cases. IMD issued advance Orange and Red alerts with 72-hour notice. Response: 127 cooling centres in Delhi, ORS at 450 community centres, 89000 doorstep wellness checks by ASHA workers, and 2.3 lakh water bottles distributed daily to construction labourers. Earliest severe April heatwave on record in Delhi since 1901.','high','reviewing',28.6139,77.2090,NOW() - INTERVAL 5 DAY,NOW()),
(7,'Flood','Chamoli District Uttarakhand — Rishi Ganga and Dhauliganga Valleys','February 7 2021: Glacier Lake Outburst Flood devastated Rishi Ganga and Dhauliganga valleys. Ice and rock mass detached from Nanda Devi glacier, triggering a flood surge at over 100 km/h through narrow Himalayan gorges. Tapovan-Vishnugad hydropower project (NTPC) and Rishi Ganga power project were completely destroyed. 204 persons killed or missing including 136 labourers at power projects. NDRF rescued 12 persons trapped in powerhouse tunnel over 72 hours. This disaster highlights extreme risks of large infrastructure in ecologically sensitive glacier zones and urgent need for GLOF early warning network.','critical','resolved',30.4191,79.3124,NOW() - INTERVAL 1800 DAY,NOW()),
(7,'Earthquake','Bhuj Anjar Bhachau Rapar in Kutch District Gujarat','The M7.7 Bhuj earthquake struck January 26 2001 at 08:46 AM IST on Republic Day killing 20,085 people and injuring 166,000. India most deadly earthquake since 1950. Entire towns of Bhuj, Anjar, and Bhachau were devastated. Over 600,000 homes destroyed and 1 million damaged. The disaster directly led to creation of Gujarat State Disaster Management Authority as the first state DMA in India, which became the model for the National Disaster Management Act 2005 and NDMA. BIS updated IS 1893 seismic building codes and comprehensively revised India earthquake zone map as a direct result.','critical','resolved',23.2420,69.6669,NOW() - INTERVAL 9200 DAY,NOW()),
(1,'Flood','Mumbai Maharashtra — Entire Metropolitan Area','July 26 2005 Mumbai deluge: 944mm of rainfall in 24 hours at Santacruz — highest single-day rainfall ever recorded in India. City paralysed: trains stranded, roads submerged, airport closed, power cut across most areas. 1094 people killed from drowning, building collapse, and electrocution. Twenty million residents affected. Economic loss estimated at Rs 15000 crore. Led directly to Brihanmumbai Storm Water Drainage project, construction of retention lakes, and establishment of Mumbai Disaster Management Plan. Annual storm drain vulnerability audits are now mandatory for all BMC wards.','critical','resolved',19.0760,72.8777,NOW() - INTERVAL 7500 DAY,NOW());
INSERT INTO resources (title, type, url, description, category, created_by, created_at, updated_at) VALUES
('NDMA India — National Disaster Management Guidelines','link','https://ndma.gov.in/Natural-Hazards','Official NDMA guidelines for all major disaster types. Includes district-level disaster management plans and training materials for all Indian states and union territories.','General',1,NOW(),NOW()),
('IMD Cyclone Tracker — Live Monitoring','link','https://mausam.imd.gov.in/imd_latest/contents/cyclone.php','India Meteorological Department real-time cyclone monitoring portal. Track active cyclones, view 5-day track forecasts, and download official IMD bulletins with wind speed and storm surge predictions.','Cyclone',1,NOW(),NOW()),
('INCOIS Tsunami Warning Portal','link','https://tsunami.incois.gov.in','Indian National Centre for Ocean Information Services. Real-time tsunami warnings, sea level gauge data, and coastal inundation maps for the Indian Ocean region.','Tsunami',1,NOW(),NOW()),
('CWC Flood Monitoring — India WRIS','link','https://indiawris.gov.in','Central Water Commission real-time data from over 5000 river gauging stations. Check flood warning status, current water levels versus danger levels, and discharge data for rivers in your district.','Flood',1,NOW(),NOW()),
('GSI Landslide Atlas of India — Bhuvan Portal','link','https://bhukosh.gsi.gov.in','Geological Survey of India interactive hazard mapping portal. View landslide susceptibility zones, active landslide inventory, and geological hazard maps by district and state.','Landslide',1,NOW(),NOW()),
('Sachet — NDMA Multi-Hazard Early Warning App','link','https://sachet.ndma.gov.in','NDMA official multi-hazard early warning system. Register your location to receive alerts for cyclones, floods, earthquakes, heatwaves, and other hazards in 12 Indian languages.','General',1,NOW(),NOW()),
('WHO First Aid Guidelines 2023','document','https://www.who.int/publications/i/item/9789240081727','World Health Organization updated first aid guidelines covering CPR, wound care, fractures, burns, heatstroke, snakebite, and drowning. International evidence-based standards used by NDRF.','Medical',1,NOW(),NOW()),
('India AQI — CPCB Real-time Air Quality','link','https://app.cpcbccr.com/AQI_India/','Central Pollution Control Board live AQI monitoring for all Indian cities. Monitor PM2.5, PM10, NO2, and SO2 levels. Essential reference during heatwaves and industrial pollution emergencies.','Heatwave',1,NOW(),NOW()),
('NDMA Earthquake Safety Videos Hindi and English','video','https://ndma.gov.in/Awareness/Videos','Official NDMA earthquake preparedness videos demonstrating Drop-Cover-Hold technique, building evacuation, search and rescue basics, and post-earthquake safety checks in 8 Indian languages.','Earthquake',1,NOW(),NOW()),
('ISRO Bhuvan Disaster Services — Satellite Imagery','link','https://bhuvan.nrsc.gov.in/disaster/','ISRO satellite imagery for real-time disaster monitoring. View flood inundation maps, cyclone damage assessment, and landslide mapping using Cartosat and Resourcesat-2 data.','General',1,NOW(),NOW()),
('NDRF Flood Rescue Operations Manual','document','https://ndrf.gov.in/sites/default/files/training_manual.pdf','Official NDRF training manual for flood rescue covering boat deployment, swift water rescue, rooftop casualty extraction, field first aid, and post-flood health protocols.','Flood',1,NOW(),NOW()),
('Kerala SDMA Flood Preparedness Guide','link','https://sdma.kerala.gov.in','State Disaster Management Authority Kerala comprehensive flood guide. Pre-monsoon household checklist, evacuation to safe zones, relief camp procedures, and post-flood recovery in Malayalam and English.','Flood',1,NOW(),NOW());
